#include<bits/stdc++.h>
using namespace std;

char a[1001][1001];
int n, m;
int dx[4] = {0, 1, 0, -1};
int dy[4] = {1, 0, -1, 0};


void dfs(int x, int y) {
	a[x][y] = '1';
	for (int i = 0; i < 4; i++) {
		int nx = x + dx[i];
		int ny = y + dy[i];
		if (nx >= 1 && nx <= n && ny >= 1 && ny <= m) {
			if (a[nx][ny] == '0') {
				dfs(nx, ny);
			}
		}
	}
}




int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			cin >> a[i][j];
		}
	}
	for (int i = 1; i <= m; i++) {
		if (a[1][i] != '*') {
			a[1][i] = '1';
		}
	}
	for (int i = 1; i <= n; i++) {
		if (a[i][1] != '*') {
			a[i][1] = '1';
		}
	}
	for (int i = 1; i <= m; i++) {
		if (a[n][i] != '*') {
			a[n][i] = '1';
		}
	}
	for (int i = 1; i <= n; i++) {
		if (a[i][m] != '*') {
			a[i][m] = '1';
		}
	}



	int s = 0;
	for (int i = 1; i <= n; i++) {
			for (int j = 1; j <= m; j++) {
				if (a[i][j] == '1') {
					dfs(i, j);
				}
			}
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= m; j++) {
			if (a[i][j] == '0') {
				s++;
			}
		}
	}

	cout << s;
	return 0;
}
